1996 |     function smartJSONParse(jsonString) {
1997 |         try {
1998 |             return JSON.parse(jsonString);
1999 |         } catch (e) {
2000 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
2001 |             let fixed = jsonString
2002 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
2003 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
2004 |                 // 2. Fix literal newlines inside strings (replace with \n)
2005 |                 .replace(/(\n)/g, (match, p1, offset) => {
2006 |                     // Only replace if we are likely inside a quoted string
2007 |                     const before = jsonString.slice(0, offset);
2008 |                     const quoteCount = (before.match(/"/g) || []).length;
2009 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
2010 |                 });
2011 | 
2012 |             try {
2013 |                 const cleanObj = JSON.parse(fixed);
2014 |                 document.getElementById('json-input').value = fixed;
2015 |                 if (typeof saveState === 'function') saveState();
2016 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
2017 |                 return cleanObj;
2018 |             } catch (e2) {
2019 |                 console.error("Robust fix failed:", e2);
2020 |                 throw e; // Throw original error for better debugging
2021 |             }
2022 |         }
2023 |     }
