2383 |                 } else {
2384 |                     // If errors remain, update list and Prompt user
2385 |                     currentErrors = scanData.errors;
2386 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2387 |                         // Recursively fix the *new* first error (since layout changed)
2388 |                         return await fixNext(0);
2389 |                     } else {
2390 |                         return false;
2391 |                     }
2392 |                 }
2393 | 
2394 |             } catch (e) {
2395 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2396 |                     return await fixNext(index);
2397 |                 } else {
2398 |                     return false;
2399 |                 }
2400 |             }
2401 |         }
2402 | 
2403 |         return await fixNext(0);
