5166 |     function formatBytes(bytes) {
5167 |         if (!bytes) return '0 B';
5168 |         const k = 1024;
5169 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5170 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5171 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5172 |     }
