5398 |             const element = document.querySelector(selector);
5399 |             
5400 |             if (element) {
5401 |                 console.log("[DeepJump] Element found. Scrolling...");
5402 |                 
5403 |                 // Wait for any tab transition animations
5404 |                 await new Promise(r => setTimeout(r, 300));
5405 | 
