5408 |                 while (curr && curr !== scrollContainer) {
5409 |                     offsetTop += curr.offsetTop;
5410 |                     curr = curr.offsetParent;
5411 |                 }
5412 | 
5413 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5414 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5415 | 
5416 |                 // Visual Highlight
5417 |                 element.style.transition = 'all 0.5s ease';
5418 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
