5423 |                 }, 3000);
5424 |                 
5425 |                 console.groupEnd();
5426 |                 return true;
5427 |             }
5428 | 
5429 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5430 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5431 |                 retryCount++;
5432 |                 showGlobalToast("🔍 Searching deeper...");
5433 |                 
5434 |                 await loadMoreFn(); 
5435 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5436 |                 return attemptNavigation();
5437 |             }
5438 | 
5439 |             console.error("[DeepJump] Failed: Element not found after retries.");
5440 |             showGlobalToast("Entry not found in recent history.", true);
5441 |             console.groupEnd();
5442 |             return false;
5443 |         };
5444 | 
5445 |         setTimeout(attemptNavigation, 100);
