5170 |     function formatBytes(bytes) {
5171 |         if (!bytes) return '0 B';
5172 |         const k = 1024;
5173 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5174 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5175 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
