5178 |     function timeAgo(dateString) {
5179 |         const date = new Date(dateString);
5180 |         const now = new Date();
5181 |         const seconds = Math.floor((now - date) / 1000);
5182 |         if (seconds < 10) return 'just now';
5183 |         if (seconds < 60) return seconds + 's ago';
5184 |         const minutes = Math.floor(seconds / 60);
5185 |         if (minutes < 60) return minutes + 'm ago';
5186 |         const hours = Math.floor(minutes / 60);
5187 |         if (hours < 24) return hours + 'h ago';
5188 |         return date.toLocaleDateString();
