5391 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5392 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5393 |         
5394 |         const navItems = document.querySelectorAll('.nav-item');
5395 |         switchTab(tabId, navItems[navIndex]);
5396 | 
5397 |         const scrollContainer = document.querySelector('.main-view');
5398 |         let retryCount = 0;
5399 |         const MAX_RETRIES = 5;
5400 | 
5401 |         const attemptNavigation = async () => {
5402 |             const element = document.querySelector(selector);
5403 |             
5404 |             if (element) {
5405 |                 console.log("[DeepJump] Element found. Scrolling...");
5406 |                 
5407 |                 // Wait for any tab transition animations
5408 |                 await new Promise(r => setTimeout(r, 300));
5409 | 
5410 |                 let offsetTop = 0;
5411 |                 let curr = element;
5412 |                 while (curr && curr !== scrollContainer) {
5413 |                     offsetTop += curr.offsetTop;
5414 |                     curr = curr.offsetParent;
5415 |                 }
5416 | 
5417 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5418 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5419 | 
5420 |                 // Visual Highlight
5421 |                 element.style.transition = 'all 0.5s ease';
5422 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5423 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5424 |                 setTimeout(() => {
5425 |                     element.style.backgroundColor = '';
5426 |                     element.style.boxShadow = '';
5427 |                 }, 3000);
5428 |                 
5429 |                 console.groupEnd();
5430 |                 return true;
5431 |             }
5432 | 
5433 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5434 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5435 |                 retryCount++;
5436 |                 showGlobalToast("🔍 Searching deeper...");
5437 |                 
5438 |                 await loadMoreFn(); 
5439 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5440 |                 return attemptNavigation();
5441 |             }
5442 | 
5443 |             console.error("[DeepJump] Failed: Element not found after retries.");
5444 |             showGlobalToast("Entry not found in recent history.", true);
5445 |             console.groupEnd();
5446 |             return false;
5447 |         };
5448 | 
5449 |         setTimeout(attemptNavigation, 100);
5450 |     }
