5804 |         report += `Scope: Last ${selected.length} entries\n\n`;
5805 |         
5806 |         selected.forEach((entry, idx) => {
5807 |             report += `### ${idx + 1}. ${entry.title.replace(/\[Auto-Fix\]/g, '🤖')}\n`;
5808 |             report += `- **Time**: ${new Date(entry.created_at).toLocaleString()}\n`;
5809 |             if (entry.sha) report += `- **Commit**: \`${entry.sha.substring(0, 7)}\`\n`;
5810 |             if (entry.note) report += `- **Note**: ${entry.note}\n`;
5811 |             
