7867 |     function extractTableNames(sql) {
7868 |         if (!sql) return [];
7869 |         const tables = [];
7870 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7871 |         
7872 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7873 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7874 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7875 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7876 | 
7877 |         let match;
7878 |         while ((match = fromRegex.exec(sql)) !== null) {
7879 |             const name = match[1];
7880 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7881 |                 tables.push(name);
7882 |             }
7883 |         }
7884 |         
7885 |         while ((match = metaRegex.exec(sql)) !== null) {
7886 |             const name = match[1];
7887 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7888 |                 tables.push(name);
7889 |             }
7890 |         }
7891 | 
7892 |         return tables;
7893 |     }
