7895 |     function convertToCSV(resultObj) {
7896 |         const data = resultObj.data || [];
7897 |         if (!data.length) return '';
7898 |         
7899 |         const tables = extractTableNames(resultObj.sql);
7900 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7901 | 
7902 |         const headers = Object.keys(data[0]);
7903 |         const rows = data.map(row => 
7904 |             headers.map(header => {
7905 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7906 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7907 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7908 |             }).join(',')
7909 |         );
7910 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7911 |     }
